from django.shortcuts import render, redirect
from django.views import View
from django.contrib import messages
from django.contrib.auth.decorators import login_required
from django.utils.decorators import method_decorator
from .models import User
from .forms import RegisterForm, LoginForm
from reservations.models import Reserva

class RegisterView(View):
    def get(self, request):
        form = RegisterForm()
        return render(request, 'accounts/register.html', {'form': form})

    def post(self, request):
        form = RegisterForm(request.POST)
        if form.is_valid():
            user = form.save()
            request.session['user_id'] = user.id
            messages.success(request, 'Registro exitoso. Bienvenido.')
            return redirect('core:home')
        return render(request, 'accounts/register.html', {'form': form})

class LoginView(View):
    def get(self, request):
        form = LoginForm()
        return render(request, 'accounts/login.html', {'form': form})

    def post(self, request):
        form = LoginForm(request.POST)
        if form.is_valid():
            email = form.cleaned_data['email']
            password = form.cleaned_data['password']
            try:
                user = User.objects.get(email=email)
                if user.check_password(password):
                    request.session['user_id'] = user.id
                    messages.success(request, 'Inicio de sesión exitoso.')
                    next_url = request.GET.get('next', 'core:home')
                    return redirect(next_url)
                else:
                    messages.error(request, 'Correo o contraseña incorrectos.')
            except User.DoesNotExist:
                messages.error(request, 'Correo o contraseña incorrectos.')
        return render(request, 'accounts/login.html', {'form': form})

class LogoutView(View):
    def post(self, request):
        if 'user_id' in request.session:
            del request.session['user_id']
        messages.success(request, 'Sesión cerrada correctamente.')
        return redirect('core:home')

@method_decorator(login_required(login_url='accounts:login'), name='dispatch')
class ProfileView(View):
    def get(self, request):
        user_id = request.session.get('user_id')
        if not user_id:
            return redirect('accounts:login')
        try:
            user = User.objects.get(id=user_id)
            reservas = Reserva.objects.filter(cliente_id=user_id).order_by('-created_at')
            return render(request, 'accounts/profile.html', {
                'user': user,
                'reservas': reservas
            })
        except User.DoesNotExist:
            return redirect('accounts:login')

from django.shortcuts import render, redirect
from django.views import View
from django.contrib import messages
from accounts.models import User

class AdminDashboardView(View):
    """Vista del panel de administración"""

    def get(self, request):
        user_id = request.session.get('user_id')
        if not user_id:
            return redirect('accounts:login')

        try:
            user = User.objects.get(id=user_id)
            if not user.es_administrador:
                messages.error(request, 'No tienes permisos para acceder al panel de administración.')
                return redirect('core:home')

            return render(request, 'admin_panel/dashboard.html', {'user': user})
        except User.DoesNotExist:
            return redirect('accounts:login')

{% extends 'base.html' %}

{% block title %}Inicio - Hundidos{% endblock %}

{% block content %}
<div style="text-align: center; margin-bottom: 40px;">
    <h2>Bienvenido a Hundidos</h2>
    <p>Tu plataforma de alquiler de barcos en línea</p>
</div>

<div style="margin-bottom: 40px;">
    <h3>Barcos Destacados</h3>
    <div style="display: grid; grid-template-columns: repeat(auto-fill, minmax(250px, 1fr)); gap: 20px; margin-top: 20px;">
        {% for barco in barcos %}
            <div style="border: 1px solid #ddd; border-radius: 8px; overflow: hidden; box-shadow: 0 2px 8px rgba(0,0,0,0.1);">
                {% if barco.imagen %}
                    <img src="{{ barco.imagen.url }}" alt="{{ barco.nombre }}" style="width: 100%; height: 200px; object-fit: cover;">
                {% else %}
                    <div style="width: 100%; height: 200px; background-color: #e0e0e0; display: flex; align-items: center; justify-content: center;">
                        <span>Sin imagen</span>
                    </div>
                {% endif %}
                <div style="padding: 15px;">
                    <h4>{{ barco.nombre }}</h4>
                    <p><strong>Categoría:</strong> {{ barco.categoria.nombre }}</p>
                    <p><strong>Fabricante:</strong> {{ barco.fabricante.nombre }}</p>
                    <p><strong>Puerto:</strong> {{ barco.puerto.nombre }}</p>
                    <p><strong>Capacidad:</strong> {{ barco.capacidad }} personas</p>
                    <p><strong>Precio:</strong> €{{ barco.precio_dia }}/día</p>
                    {% if barco.disponible %}
                        <a href="{% url 'catalog:barco_detail' barco.id %}" class="btn" style="display: block; text-align: center; margin-top: 10px;">Ver Detalles</a>
                    {% else %}
                        <button class="btn" disabled style="display: block; width: 100%; margin-top: 10px; opacity: 0.5; cursor: not-allowed;">No Disponible</button>
                    {% endif %}
                </div>
            </div>
        {% empty %}
            <p>No hay barcos disponibles en este momento.</p>
        {% endfor %}
    </div>
</div>

<div style="text-align: center; margin-top: 40px;">
    <a href="{% url 'catalog:barco_list' %}" class="btn" style="padding: 12px 30px; font-size: 16px;">Ver Catálogo Completo</a>
</div>
{% endblock %}
